import{_ as l,C as s,o as h,c as m,a1 as a,E as r,w as o,a as n,j as t}from"./chunks/framework.BX4nIuL2.js";const _=JSON.parse('{"title":"FDM - machine operation","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/4.FDM-machineoperation.md","filePath":"courses/fab-course/doc/3_3dprinter/4.FDM-machineoperation.md"}'),p={name:"courses/fab-course/doc/3_3dprinter/4.FDM-machineoperation.md"};function d(c,e,u,f,g,w){const i=s("center");return h(),m("div",null,[e[3]||(e[3]=a('<h1 id="fdm-machine-operation" tabindex="-1">FDM - machine operation <a class="header-anchor" href="#fdm-machine-operation" aria-label="Permalink to &quot;FDM - machine operation&quot;">​</a></h1><h2 id="_1-software-settiing" tabindex="-1">1. Software settiing <a class="header-anchor" href="#_1-software-settiing" aria-label="Permalink to &quot;1.  Software settiing&quot;">​</a></h2><p>When we have a 3D model and are ready to print, we need a program that prepares your file for your 3D printer. A slicing program takes an STL or OBJ file and creates G-code, the code that instructs your 3D printer where to move the print head to, how fast to move it, and what path to follow. Cura is Ultimaker’s slicing software and it is one of the biggest open source 3D printing software .(reference from <a href="https://ultimaker.com/en/resources/education/3d-printing-in-the-classroom" target="_blank" rel="noreferrer">Cura</a>) .In addition ,you can use <a href="https://www.simplify3d.com/" target="_blank" rel="noreferrer">Simplify 3D</a>,<a href="https://www.repetier.com/" target="_blank" rel="noreferrer">Repetier</a>,<a href="https://slic3r.org/" target="_blank" rel="noreferrer">Slic3r</a></p><h2 id="_2-choice-the-model" tabindex="-1">2. Choice the model <a class="header-anchor" href="#_2-choice-the-model" aria-label="Permalink to &quot;2. Choice the model&quot;">​</a></h2><ul><li>Click the button(Open file) and choice the model we need to print</li><li>Also we can use mouse to put the stl format into the Cura</li><li>Normal we would use STL,OBJ format ,and some time will use AMF for special requirement</li></ul><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/stlsmf.png" alt=""></p>',6)),r(i,null,{default:o(()=>[...e[0]||(e[0]=[n(" STL and 3MF format",-1)])]),_:1}),e[4]||(e[4]=a('<h2 id="_3-locate-the-model-the-model" tabindex="-1">3. Locate the model the model <a class="header-anchor" href="#_3-locate-the-model-the-model" aria-label="Permalink to &quot;3.  Locate the model the model&quot;">​</a></h2><p>I use move ,scale to locate the model</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/FDMSOFTWARE2.png" alt=""> We must make sure the model in the software is yellow, or it would has problem.</p><h2 id="_4-3d-printer-parameter-setting" tabindex="-1">4. 3D printer parameter Setting <a class="header-anchor" href="#_4-3d-printer-parameter-setting" aria-label="Permalink to &quot;4. 3D printer parameter Setting&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/parameter.png" alt=""></p><ul><li><p>Quality(Layer height:0.1mm ),it is one of the most often changed settings. It means the thickness of one printed layer (in mm). With a thinner layer height you will usually increase the quality of the print, leading to a smoother surface and more detail visible in the Z-direction (height) of the model. On the other hand, by using thicker layers you can decrease the print time substantially.</p></li><li><p>Shell(wall thickness0.8mm, top thickness1.6mm, bottom thickness 1.6mm).Wall Thickness adjusts the thickness of outside walls (on the X/Y axis) of the model.It is generally a multiple of the line width(in our machine is 0.4mm). In general a wall thickness of 2 or 3 times the line width is sufficient.</p></li><li><p>Infill(5%infill density)—Settings related to the inside of the print. Infill density defines the amount of plastic used on the inside of the print. A higher infill density means that there’s more plastic on the inside of your print, leading to a stronger object. An infill density between 10% and 20% will be enough for most objects though.</p></li><li><p>Material(temperature is 200,and Diameter i 3mm)—Settings related to Material. It depend on material. Normal vendor will give us the reference parameter.And we need to test it.In our test ,the temperature is 200, and Diameter is 3mm</p></li><li><p>Speed(Infill speed(60)mWall speed(30),Top/bottom speed(20))—Speeds at which the print head moves while printing. A higher print speed will lead to a shorter print time and the effect would a little worse</p></li><li><p>Cooling(yes)—Settings that define how the plastic is cooled. I enable the print head fans during printing because cooling will increase the print quality.</p></li><li><p>Support(yes)—Options for support structures. Because my models have overhanging parts,I use a support structure under the model to prevent the plastic from falling down</p></li><li><p>Platform adhesion(Brim)—Options for how your model relates to the build plate. Options include<a href="http://www.references3d.com/brim-ou-raft/#.WubC6FOFM1I" target="_blank" rel="noreferrer"> Brim, Raft, and Skirt</a>.</p></li></ul><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/FDMSUPPORT.png" alt=""></p>',7)),r(i,null,{default:o(()=>[...e[1]||(e[1]=[n(" Support for model ",-1)])]),_:1}),e[5]||(e[5]=t("p",null,[t("img",{src:"https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdminfill.png",alt:""})],-1)),r(i,null,{default:o(()=>[...e[2]||(e[2]=[n(" Infill density for model",-1)])]),_:1}),e[6]||(e[6]=a('<h2 id="_5-load-material" tabindex="-1">5. Load material <a class="header-anchor" href="#_5-load-material" aria-label="Permalink to &quot;5. Load material&quot;">​</a></h2><p>Load material according to the below picture.I need push the material into the inlet of machine.</p><h2 id="_6-check-the-platform" tabindex="-1">6. Check the platform <a class="header-anchor" href="#_6-check-the-platform" aria-label="Permalink to &quot;6. Check the platform&quot;">​</a></h2><p>Rotate the bolt under the platform to change the heigh of platform. Use paper to check it. It is OK if there is resist during moving the paper.</p><h2 id="_7-operation-the-machine" tabindex="-1">7. Operation the machine <a class="header-anchor" href="#_7-operation-the-machine" aria-label="Permalink to &quot;7. Operation the machine&quot;">​</a></h2><ul><li>Open the main power of machine</li><li>Use switch to choice<code>Print from SD-3D body </code></li><li>Wait for printing;</li><li>After finish ,take it away from platform slowly</li></ul>',6)),e[7]||(e[7]=t("div",{style:{position:"relative",height:"0","padding-bottom":"56.25%"}},[t("iframe",{src:"https://www.youtube.com/embed/-tKWBFOT9_w?ecver=2",width:"640",height:"360",frameborder:"0",allow:"autoplay; encrypted-media",style:{position:"absolute",width:"100%",height:"100%",left:"0"},allowfullscreen:""})],-1))])}const y=l(p,[["render",d]]);export{_ as __pageData,y as default};
